class Solution:
    def findMinArrowShots(self, points):
        # Brute-force: sort by start, try every possible arrow position greedily
        points = sorted(points, key=lambda p: p[1])
        arrows = 0
        arrow_pos = float('-inf')
        for xstart, xend in points:
            if xstart > arrow_pos:
                arrows += 1
                arrow_pos = xend
        return arrows

