var findMinArrowShots = function(points) {
    points.sort((a, b) => a[1] - b[1]);
    let arrows = 0;
    let arrowPos = -Infinity;
    for (const [xstart, xend] of points) {
        if (xstart > arrowPos) {
            arrows++;
            arrowPos = xend;
        }
    }
    return arrows;
};
